	repo, err := store.CreateRepository(input.Name, repoPath)
	if err != nil {
		return nil, fmt.Errorf("creating repository: %w", err)
	}

	// Persist remote URL and auth token early so they survive if the background
	// goroutine fails and the user retries via reindex.
