	if isRemote {
		meta.RemoteURL = normalizeGitURL(repoPath)
		if input.Token != nil && *input.Token != "" {
			meta.AuthToken = *input.Token
		}
	}
	store.UpdateRepositoryMeta(repo.ID, meta)

	r.Resolver.publishEvent(events.EventRepoIndexStarted, map[string]interface{}{
		"repo_id": repo.ID, "repo_name": repo.Name,
	})

	// Run clone + index in the background so the HTTP request returns immediately
	// and doesn't block health probes.
	go r.importRepository(repo.ID, input.Name, repoPath, isRemote, input.Token)

