// VerifyLink is the resolver for the verifyLink field.
func (r *mutationResolver) VerifyLink(ctx context.Context, linkID string, verified bool) (*RequirementLink, error) {
	if r.getStore(ctx) == nil {
		return nil, fmt.Errorf("store not initialized")
	}
	link := r.getStore(ctx).VerifyLink(linkID, verified, "graphql-user")
	if link == nil {
		return nil, fmt.Errorf("link not found: %s", linkID)
	}
	if verified {
		r.Resolver.publishEvent(events.EventLinkVerified, map[string]interface{}{"link_id": linkID})
	} else {
		r.Resolver.publishEvent(events.EventLinkRejected, map[string]interface{}{"link_id": linkID})
	}
	return mapLinkWithRelations(link, r.getStore(ctx)), nil
}

// CreateManualLink is the resolver for the createManualLink field.
func (r *mutationResolver) CreateManualLink(ctx context.Context, input CreateManualLinkInput) (*RequirementLink, error) {
	if r.getStore(ctx) == nil {
		return nil, fmt.Errorf("store not initialized")
	}
	rationale := ""
	if input.Rationale != nil {
		rationale = *input.Rationale
	}
	link := r.getStore(ctx).StoreLink(input.RepositoryID, &graphstore.StoredLink{
		RequirementID: input.RequirementID,
		SymbolID:      input.SymbolID,
		Confidence:    1.0,
		Source:        "manual",
		LinkType:      "implements",
		Rationale:     rationale,
		Verified:      true,
		VerifiedBy:    "graphql-user",
	})
	if link == nil {
		return nil, fmt.Errorf("failed to create link")
	}
	return mapLinkWithRelations(link, r.getStore(ctx)), nil
}

// AnalyzeSymbol is the resolver for the analyzeSymbol field.
func (r *mutationResolver) AnalyzeSymbol(ctx context.Context, repositoryID string, symbolID string) (*AnalysisResult, error) {
	if r.Worker == nil {
		return nil, fmt.Errorf("AI features are unavailable: worker not connected")
	}
	if r.getStore(ctx) == nil {
		return nil, fmt.Errorf("store not initialized")
	}

	sym := r.getStore(ctx).GetSymbol(symbolID)
	if sym == nil {
		return nil, fmt.Errorf("symbol not found: %s", symbolID)
	}

	repo := r.getStore(ctx).GetRepository(repositoryID)
	repoRoot, err := resolveRepoSourcePath(repo)
	if err != nil {
		return nil, fmt.Errorf("source unavailable: %w", err)
	}

	fileContent, err := readSourceFile(repoRoot, sym.FilePath)
	if err != nil {
		return nil, fmt.Errorf("reading source: %w", err)
	}

	symbolContext := extractSymbolContext(fileContent, sym.StartLine, sym.EndLine)

	ctx = r.withModelMetadata(ctx, "analysis")
	var resp *reasoningv1.AnalyzeSymbolResponse
	err = r.runSyncLLMJob(ctx, llm.SubsystemReasoning, "analyze_symbol",
		fmt.Sprintf("reasoning:analyze_symbol:%s:%s", repositoryID, sym.ID),
		repositoryID,
		func(rt llm.Runtime) error {
			var callErr error
			resp, callErr = r.Worker.AnalyzeSymbol(ctx, &reasoningv1.AnalyzeSymbolRequest{
				RepositoryId: repositoryID,
				Symbol: &commonv1.CodeSymbol{
					Id:            sym.ID,
					Name:          sym.Name,
					QualifiedName: sym.QualifiedName,
					Kind:          commonv1.SymbolKind(commonv1.SymbolKind_value["SYMBOL_KIND_"+strings.ToUpper(sym.Kind)]),
					Language:      languageToProto(sym.Language),
					Location: &commonv1.FileLocation{
						Path:      sym.FilePath,
						StartLine: int32(sym.StartLine),
						EndLine:   int32(sym.EndLine),
					},
					Signature:  sym.Signature,
					DocComment: sym.DocComment,
				},
				SurroundingContext: symbolContext,
			})
			if callErr != nil {
				return callErr
			}
			if resp.Usage != nil {
				rt.ReportTokens(int(resp.Usage.InputTokens), int(resp.Usage.OutputTokens))
			}
			return nil
		})
	if err != nil {
		return nil, fmt.Errorf("worker analyze failed: %w", err)
	}

	result := &AnalysisResult{
		Summary:     resp.Summary,
		Purpose:     resp.Purpose,
		Concerns:    resp.Concerns,
		Suggestions: resp.Suggestions,
	}
	if resp.Usage != nil {
		result.Model = &resp.Usage.Model
		inTok := int(resp.Usage.InputTokens)
		outTok := int(resp.Usage.OutputTokens)
		result.InputTokens = &inTok
		result.OutputTokens = &outTok
		r.getStore(ctx).StoreLLMUsage(&graphstore.LLMUsageRecord{
			RepoID: repositoryID, Provider: resp.Usage.Model, Model: resp.Usage.Model,
			Operation: "analyze_symbol", InputTokens: int(resp.Usage.InputTokens), OutputTokens: int(resp.Usage.OutputTokens),
		})
	}
	return result, nil
}

// DiscussCode is the resolver for the discussCode field.
func (r *mutationResolver) DiscussCode(ctx context.Context, input DiscussCodeInput) (*DiscussionResult, error) {
	if r.Worker == nil {
		return nil, fmt.Errorf("AI features are unavailable: worker not connected")
	}

	slog.Info("discuss_code_request",
		"repository_id", input.RepositoryID,
		"client_type", clientTypeFromContext(ctx),
		"has_requirement_id", input.RequirementID != nil && *input.RequirementID != "",
		"has_artifact_id", input.ArtifactID != nil && *input.ArtifactID != "",
	)

	contextParts := make([]string, 0, 4)
	if input.ConversationHistory != nil && len(input.ConversationHistory) > 0 {
		contextParts = append(contextParts, "Recent follow-up context:\n"+strings.Join(input.ConversationHistory, "\n\n"))
	}
	if input.ArtifactID != nil && *input.ArtifactID != "" && r.KnowledgeStore != nil {
		if artifact := r.KnowledgeStore.GetKnowledgeArtifact(*input.ArtifactID); artifact != nil {
			contextParts = append(contextParts, discussionContextFromArtifact(artifact))
		}
	}
	if input.RequirementID != nil && *input.RequirementID != "" {
		if req := r.getStore(ctx).GetRequirement(*input.RequirementID); req != nil {
			contextParts = append(contextParts, fmt.Sprintf(
				"Requirement context:\nID: %s\nTitle: %s\nDescription: %s",
				req.ExternalID, req.Title, req.Description,
			))
		}
	}

	// Prefer provided code; otherwise use indexed symbol context; finally fall back to file reads.
	var contextCode string
	if input.Code != nil && *input.Code != "" {
		contextCode = *input.Code
		contextParts = append(contextParts, contextCode)
	} else if input.SymbolID != nil && *input.SymbolID != "" {
		if sym := r.getStore(ctx).GetSymbol(*input.SymbolID); sym != nil {
			contextParts = append(contextParts, discussionContextFromStoredSymbol(sym))
			if input.FilePath == nil || *input.FilePath == "" {
				filePath := sym.FilePath
				input.FilePath = &filePath
			}
			// Also read the actual source file so the LLM has full code context, not just metadata.
			if input.FilePath != nil && *input.FilePath != "" {
				repo := r.getStore(ctx).GetRepository(input.RepositoryID)
				repoRoot, err := resolveRepoSourcePath(repo)
				if err == nil {
					content, err := readSourceFile(repoRoot, *input.FilePath)
					if err == nil && content != "" {
						contextParts = append(contextParts, content)
					}
				}
			}
		}
	}
	if len(contextParts) == 0 && input.FilePath != nil && *input.FilePath != "" {
		repo := r.getStore(ctx).GetRepository(input.RepositoryID)
		repoRoot, err := resolveRepoSourcePath(repo)
		if err != nil {
			return nil, fmt.Errorf("source unavailable: %w", err)
		}
		content, err := readSourceFile(repoRoot, *input.FilePath)
		if err != nil {
			return nil, fmt.Errorf("reading source: %w", err)
		}
		contextParts = append(contextParts, content)
	}
	contextCode = strings.TrimSpace(strings.Join(contextParts, "\n\n"))

	if contextCode == "" {
		return nil, fmt.Errorf("provide code, filePath, artifactId, or symbolId")
	}

	lang := commonv1.Language_LANGUAGE_UNSPECIFIED
	if input.Language != nil {
		lang = languageToProto(input.Language.String())
	} else if input.FilePath != nil && *input.FilePath != "" {
		lang = deriveLanguage(*input.FilePath)
	}

	// Build context symbols from the code
	var contextSymbols []*commonv1.CodeSymbol
	if input.SymbolID != nil && *input.SymbolID != "" {
		if sym := r.getStore(ctx).GetSymbol(*input.SymbolID); sym != nil {
			contextSymbols = append(contextSymbols, protoCodeSymbolFromStored(sym))
		}
	}
	if input.FilePath != nil {
		syms := r.getStore(ctx).GetSymbolsByFile(input.RepositoryID, *input.FilePath)
		for _, s := range syms {
			contextSymbols = append(contextSymbols, &commonv1.CodeSymbol{
				Id:   s.ID,
				Name: s.Name,
			})
		}
	}

	ctx = r.withModelMetadata(ctx, "discussion")
	var resp *reasoningv1.AnswerQuestionResponse
	filePathArg := ""
	if input.FilePath != nil {
		filePathArg = *input.FilePath
	}
	targetKey := fmt.Sprintf("reasoning:discuss:%s:%s:%s",
		input.RepositoryID, filePathArg, hashString(input.Question))
	err := r.runSyncLLMJob(ctx, llm.SubsystemReasoning, "discuss_code", targetKey, input.RepositoryID,
		func(rt llm.Runtime) error {
			var callErr error
			resp, callErr = r.Worker.AnswerQuestion(ctx, &reasoningv1.AnswerQuestionRequest{
				Question:       input.Question,
				RepositoryId:   input.RepositoryID,
				ContextSymbols: contextSymbols,
				MaxTokens:      4096,
				ContextCode:    contextCode,
				Language:       lang,
				FilePath:       filePathArg,
			})
			if callErr != nil {
				return callErr
			}
			if resp.Usage != nil {
				rt.ReportTokens(int(resp.Usage.InputTokens), int(resp.Usage.OutputTokens))
			}
			return nil
		})
	if err != nil {
		return nil, fmt.Errorf("worker discuss failed: %w", err)
	}

	result := &DiscussionResult{
		Answer:              resp.Answer,
		References:          []string{},
		RelatedRequirements: []string{},
	}
	for _, sym := range resp.ReferencedSymbols {
		ref := sym.QualifiedName
		if ref == "" {
			ref = sym.Name
		}
		if ref != "" {
			result.References = append(result.References, ref)
		}
	}

	// Populate relatedRequirements from linked requirements for context symbols.
	seenReqs := map[string]bool{}
	store := r.getStore(ctx)
	for _, cs := range contextSymbols {
		for _, link := range store.GetLinksForSymbol(cs.Id, false) {
			if seenReqs[link.RequirementID] {
				continue
			}
			seenReqs[link.RequirementID] = true
			if req := store.GetRequirement(link.RequirementID); req != nil {
				label := req.ExternalID
				if label == "" {
					label = req.Title
				}
				if label != "" {
					result.RelatedRequirements = append(result.RelatedRequirements, label)
				}
			}
		}
	}

	if resp.Usage != nil {
		result.Model = &resp.Usage.Model
		inTok := int(resp.Usage.InputTokens)
		outTok := int(resp.Usage.OutputTokens)
		result.InputTokens = &inTok
		result.OutputTokens = &outTok
		store.StoreLLMUsage(&graphstore.LLMUsageRecord{
			RepoID: input.RepositoryID, Provider: resp.Usage.Model, Model: resp.Usage.Model,
			Operation: "discuss_code", InputTokens: int(resp.Usage.InputTokens), OutputTokens: int(resp.Usage.OutputTokens),
		})
	}
	return result, nil
}

// ReviewCode is the resolver for the reviewCode field.
func (r *mutationResolver) ReviewCode(ctx context.Context, input ReviewCodeInput) (*ReviewResult, error) {
	if r.Worker == nil {
		return nil, fmt.Errorf("AI features are unavailable: worker not connected")
	}

	content := ""
	if input.Code != nil && *input.Code != "" {
		content = *input.Code
	} else {
		repo := r.getStore(ctx).GetRepository(input.RepositoryID)
		repoRoot, err := resolveRepoSourcePath(repo)
		if err != nil {
			return nil, fmt.Errorf("source unavailable: %w", err)
		}

		readContent, err := readSourceFile(repoRoot, input.FilePath)
		if err != nil {
			return nil, fmt.Errorf("reading source: %w", err)
		}
		content = readContent
	}

	lang := deriveLanguage(input.FilePath)
	if input.Language != nil {
		lang = languageToProto(input.Language.String())
	}

	ctx = r.withModelMetadata(ctx, "review")
	var resp *reasoningv1.ReviewFileResponse
	err := r.runSyncLLMJob(ctx, llm.SubsystemReasoning, "review_code",
		fmt.Sprintf("reasoning:review:%s:%s:%s", input.RepositoryID, input.FilePath, input.Template),
		input.RepositoryID,
		func(rt llm.Runtime) error {
			var callErr error
			resp, callErr = r.Worker.ReviewFile(ctx, &reasoningv1.ReviewFileRequest{
				RepositoryId: input.RepositoryID,
				FilePath:     input.FilePath,
				Language:     lang,
				Content:      content,
				Template:     input.Template,
			})
			if callErr != nil {
				return callErr
			}
			if resp.Usage != nil {
				rt.ReportTokens(int(resp.Usage.InputTokens), int(resp.Usage.OutputTokens))
			}
			return nil
		})
	if err != nil {
		return nil, fmt.Errorf("worker review failed: %w", err)
	}

	result := &ReviewResult{
		Template: resp.Template,
		Score:    float64(resp.Score),
		Findings: make([]*ReviewFinding, 0, len(resp.Findings)),
	}
	for _, f := range resp.Findings {
		finding := &ReviewFinding{
			Category: f.Category,
			Severity: f.Severity,
			Message:  f.Message,
		}
		if f.FilePath != "" {
			finding.FilePath = &f.FilePath
		}
		if f.StartLine > 0 {
			sl := int(f.StartLine)
			finding.StartLine = &sl
		}
		if f.EndLine > 0 {
			el := int(f.EndLine)
			finding.EndLine = &el
		}
		if f.Suggestion != "" {
			finding.Suggestion = &f.Suggestion
		}
		result.Findings = append(result.Findings, finding)
	}
	if resp.Usage != nil {
		result.Model = &resp.Usage.Model
		inTok := int(resp.Usage.InputTokens)
		outTok := int(resp.Usage.OutputTokens)
		result.InputTokens = &inTok
		result.OutputTokens = &outTok
		r.getStore(ctx).StoreLLMUsage(&graphstore.LLMUsageRecord{
			RepoID: input.RepositoryID, Provider: resp.Usage.Model, Model: resp.Usage.Model,
			Operation: "review_code", InputTokens: int(resp.Usage.InputTokens), OutputTokens: int(resp.Usage.OutputTokens),
		})
	}

	r.Resolver.publishEvent(events.EventReviewCompleted, map[string]interface{}{
		"repo_id": input.RepositoryID, "file_path": input.FilePath,
		"template": input.Template, "findings": len(result.Findings),
	})

	return result, nil
}

// AutoLinkRequirements is the resolver for the autoLinkRequirements field.
func (r *mutationResolver) AutoLinkRequirements(ctx context.Context, repositoryID string, minConfidence *float64) (*AutoLinkResult, error) {
	if r.Worker == nil {
		return nil, fmt.Errorf("AI features are unavailable: worker not connected")
	}

	repo := r.getStore(ctx).GetRepository(repositoryID)
	if repo == nil {
		return nil, fmt.Errorf("repository not found: %s", repositoryID)
	}

	repoRoot, err := resolveRepoSourcePath(repo)
	if err != nil {
		return nil, fmt.Errorf("source unavailable: %w", err)
	}

	minConf := float32(0.5)
	if minConfidence != nil {
		minConf = float32(*minConfidence)
	}

	// Load all requirements
	reqs, _ := r.getStore(ctx).GetRequirements(repositoryID, 10000, 0)
	if len(reqs) == 0 {
		return &AutoLinkResult{Links: []*RequirementLink{}}, nil
	}

	// Load candidate symbols in batches
	allSyms, _ := r.getStore(ctx).GetSymbols(repositoryID, nil, nil, 10000, 0)

	// Build candidate symbols with source content
	candidates := make([]*linkingv1.CandidateSymbol, 0, len(allSyms))
	sourceCache := make(map[string]string) // filePath -> content

	for _, sym := range allSyms {
		content, ok := sourceCache[sym.FilePath]
		if !ok {
			c, err := readSourceFile(repoRoot, sym.FilePath)
			if err != nil {
				continue // skip symbols whose source is unreadable
			}
			sourceCache[sym.FilePath] = c
			content = c
		}

		symContent := extractSymbolContext(content, sym.StartLine, sym.EndLine)
		candidates = append(candidates, &linkingv1.CandidateSymbol{
			Symbol: &commonv1.CodeSymbol{
				Id:            sym.ID,
				Name:          sym.Name,
				QualifiedName: sym.QualifiedName,
				Kind:          commonv1.SymbolKind(commonv1.SymbolKind_value["SYMBOL_KIND_"+strings.ToUpper(sym.Kind)]),
				Language:      languageToProto(sym.Language),
				Location: &commonv1.FileLocation{
					Path:      sym.FilePath,
					StartLine: int32(sym.StartLine),
					EndLine:   int32(sym.EndLine),
				},
				Signature:  sym.Signature,
				DocComment: sym.DocComment,
			},
			Content: symContent,
		})
	}

	// Build proto requirements for the batch call
	protoReqs := make([]*commonv1.Requirement, 0, len(reqs))
	for _, req := range reqs {
		protoReqs = append(protoReqs, &commonv1.Requirement{
			Id:          req.ID,
			ExternalId:  req.ExternalID,
			Title:       req.Title,
			Description: req.Description,
			Priority:    req.Priority,
			Tags:        req.Tags,
		})
	}

	slog.Info("auto-link: starting batch link", "requirements", len(protoReqs), "candidates", len(candidates))

	// Use BatchLink for a single gRPC call — entity embeddings are computed once
	// and reused across all requirements by the worker. Routed through the
	// orchestrator so this shows up on the Monitor page alongside knowledge /
	// reasoning work and can be deduped across rapid repeated invocations.
	var resp *linkingv1.BatchLinkResponse
	if err := r.runSyncLLMJob(context.Background(), llm.SubsystemLinking, "batch_link",
		fmt.Sprintf("linking:batch:%s", repositoryID), repositoryID,
		func(rt llm.Runtime) error {
			var callErr error
			resp, callErr = r.Worker.BatchLink(context.Background(), &linkingv1.BatchLinkRequest{
				Requirements:     protoReqs,
				RepositoryId:     repositoryID,
				MinConfidence:    minConf,
				CandidateSymbols: candidates,
			})
			return callErr
		}); err != nil {
		return nil, fmt.Errorf("batch link failed: %w", err)
	}

	// Convert proto links to StoredLink objects for bulk insert
	storedLinks := make([]*graphstore.StoredLink, 0, len(resp.Links))
	for _, link := range resp.Links {
		storedLinks = append(storedLinks, &graphstore.StoredLink{
			RequirementID: link.RequirementId,
			SymbolID:      link.SymbolId,
			Confidence:    protoConfidenceToFloat(link.Confidence),
			Source:        "semantic",
			LinkType:      "implements",
			Rationale:     link.Rationale,
		})
	}

	slog.Info("auto-link: storing links", "count", len(storedLinks))
	store := r.getStore(ctx)
	stored := store.StoreLinks(repositoryID, storedLinks)
	slog.Info("auto-link: storage complete", "stored", stored)

	r.Resolver.publishEvent(events.EventRequirementLinked, map[string]interface{}{
		"repo_id": repositoryID, "links_created": stored,
		"requirements_processed": int(resp.RequirementsProcessed),
	})

	return &AutoLinkResult{
		LinksCreated:          stored,
		RequirementsProcessed: int(resp.RequirementsProcessed),
		Links:                 []*RequirementLink{},
	}, nil
}

// EnrichRequirement is the resolver for the enrichRequirement field.
func (r *mutationResolver) EnrichRequirement(ctx context.Context, requirementID string) (*Requirement, error) {
	if r.Worker == nil {
		return nil, fmt.Errorf("AI features are unavailable: worker not connected")
	}

	req := r.getStore(ctx).GetRequirement(requirementID)
	if req == nil {
		return nil, fmt.Errorf("requirement not found: %s", requirementID)
	}

	ctx = r.withModelMetadata(ctx, "analysis")
	var resp *requirementsv1.EnrichRequirementResponse
	err := r.runSyncLLMJob(ctx, llm.SubsystemRequirements, "enrich_requirement",
		fmt.Sprintf("requirements:enrich:%s", req.ID), "",
		func(rt llm.Runtime) error {
			var callErr error
			resp, callErr = r.Worker.EnrichRequirement(ctx, &requirementsv1.EnrichRequirementRequest{
				Requirement: &commonv1.Requirement{
					Id:          req.ID,
					ExternalId:  req.ExternalID,
					Title:       req.Title,
					Description: req.Description,
					Priority:    req.Priority,
					Tags:        req.Tags,
				},
			})
			if callErr != nil {
				return callErr
			}
			if resp.Usage != nil {
				rt.ReportTokens(int(resp.Usage.InputTokens), int(resp.Usage.OutputTokens))
			}
			return nil
		})
	if err != nil {
		return nil, fmt.Errorf("worker enrich failed: %w", err)
	}

	// Persist the enrichment results
	newPriority := req.Priority
	if resp.SuggestedPriority != "" {
		newPriority = resp.SuggestedPriority
	}
	newTags := req.Tags
	if len(resp.SuggestedTags) > 0 {
		// Merge suggested tags with existing ones
		tagSet := make(map[string]bool)
		for _, t := range req.Tags {
			tagSet[t] = true
		}
		for _, t := range resp.SuggestedTags {
			tagSet[t] = true
		}
		newTags = make([]string, 0, len(tagSet))
		for t := range tagSet {
			newTags = append(newTags, t)
		}
	}

	updated := r.getStore(ctx).UpdateRequirement(requirementID, newPriority, newTags)
	if updated == nil {
		return nil, fmt.Errorf("failed to update requirement: %s", requirementID)
	}
	return mapRequirement(updated), nil
}

// SimulateChange is the resolver for the simulateChange field.
func (r *mutationResolver) SimulateChange(ctx context.Context, input SimulateChangeInput) (*SimulatedImpactReport, error) {
	if r.Worker == nil {
		return nil, fmt.Errorf("AI features are unavailable: worker not connected")
	}

	store := r.getStore(ctx)
	repo := store.GetRepository(input.RepositoryID)
	if repo == nil {
		return nil, fmt.Errorf("repository not found: %s", input.RepositoryID)
	}

	desc := strings.TrimSpace(input.Description)
	if desc == "" {
		return nil, fmt.Errorf("description must be non-empty")
	}
	if len(desc) > 2000 {
		return nil, fmt.Errorf("description must be 2000 characters or fewer")
	}

	// Load all symbols for the repo
	allSyms, _ := store.GetSymbols(input.RepositoryID, nil, nil, 10000, 0)
	if len(allSyms) == 0 {
		return nil, fmt.Errorf("repository has no indexed symbols")
	}

	// Build proto symbols
	protoSymbols := make([]*commonv1.CodeSymbol, 0, len(allSyms))
	for _, sym := range allSyms {
		protoSymbols = append(protoSymbols, &commonv1.CodeSymbol{
			Id:            sym.ID,
			Name:          sym.Name,
			QualifiedName: sym.QualifiedName,
			Kind:          commonv1.SymbolKind(commonv1.SymbolKind_value["SYMBOL_KIND_"+strings.ToUpper(sym.Kind)]),
			Language:      languageToProto(sym.Language),
			Location: &commonv1.FileLocation{
				Path:      sym.FilePath,
				StartLine: int32(sym.StartLine),
				EndLine:   int32(sym.EndLine),
			},
			Signature:  sym.Signature,
			DocComment: sym.DocComment,
		})
	}

	anchorFile := ""
	if input.AnchorFile != nil {
		anchorFile = *input.AnchorFile
	}
	anchorSymbol := ""
	if input.AnchorSymbol != nil {
		anchorSymbol = *input.AnchorSymbol
	}

	slog.Info("simulate-change: resolving symbols", "repo", repo.Name, "symbols", len(protoSymbols), "descLen", len(desc))

	resp, err := r.Worker.SimulateChange(ctx, &reasoningv1.SimulateChangeRequest{
		RepositoryId: input.RepositoryID,
		Description:  desc,
		AnchorFile:   anchorFile,
		AnchorSymbol: anchorSymbol,
		Symbols:      protoSymbols,
	})
	if err != nil {
		return nil, fmt.Errorf("simulation failed: %w", err)
	}

	// Determine call graph expansion depth
	maxDepth := 2
	if len(allSyms) > 50000 {
		maxDepth = 1
	}

	// Expand via call graph and compute impact
	expandedChanges := graphstore.ExpandViaCallGraph(store, resp.ResolvedSymbols, maxDepth)
	fileDiffs, _ := graphstore.BuildSimulatedChanges(resp.ResolvedSymbols)
	report := graphstore.ComputeImpact(store, input.RepositoryID, fileDiffs, expandedChanges)

	// Mark as simulated
	report.ID = fmt.Sprintf("sim-%s-%d", input.RepositoryID, time.Now().UnixMilli())
	report.OldCommitSHA = ""
	report.NewCommitSHA = ""

	// Build resolved symbols for the response
	resolvedSymbols := make([]*ResolvedSymbol, 0, len(resp.ResolvedSymbols))
	for _, rs := range resp.ResolvedSymbols {
		resolvedSymbols = append(resolvedSymbols, &ResolvedSymbol{
			SymbolID:      rs.SymbolId,
			Name:          rs.Name,
			QualifiedName: rs.QualifiedName,
			Kind:          rs.Kind,
			FilePath:      rs.FilePath,
			Similarity:    float64(rs.Similarity),
			IsAnchor:      rs.IsAnchor,
		})
	}

	now := time.Now().UTC()
	return &SimulatedImpactReport{
		ID:              report.ID,
		Simulated:       true,
		Description:     desc,
		AnchorFile:      input.AnchorFile,
		AnchorSymbol:    input.AnchorSymbol,
		ResolvedSymbols: resolvedSymbols,
		Report:          mapImpactReport(report),
		ComputedAt:      now,
	}, nil
}

// TriggerSpecExtraction is the resolver for the triggerSpecExtraction field.
func (r *mutationResolver) TriggerSpecExtraction(ctx context.Context, input TriggerSpecExtractionInput) (*SpecExtractionResult, error) {
	if r.Worker == nil {
		return nil, fmt.Errorf("AI features are unavailable: worker not connected")
	}

	store := r.getStore(ctx)
	repo := store.GetRepository(input.RepositoryID)
	if repo == nil {
		return nil, fmt.Errorf("repository not found: %s", input.RepositoryID)
	}

	repoRoot, err := resolveRepoSourcePath(repo)
	if err != nil {
		return nil, fmt.Errorf("source unavailable: %w", err)
	}

	// Gather source files suitable for spec extraction
	files := store.GetFiles(input.RepositoryID)
	var protoFiles []*requirementsv1.FileEntry
	for _, f := range files {
		content, err := readSourceFileLimited(repoRoot, f.Path, 512*1024) // 512KB limit
		if err != nil {
			continue
		}
		protoFiles = append(protoFiles, &requirementsv1.FileEntry{
			Path:      f.Path,
			Content:   content,
			Language:  f.Language,
			LineCount: int32(f.LineCount),
		})
	}

	if len(protoFiles) == 0 {
		return &SpecExtractionResult{Warnings: []string{"no readable source files found"}}, nil
	}

	skipLLM := input.SkipLlmRefinement != nil && *input.SkipLlmRefinement

	slog.Info("spec-extraction: starting", "repo", repo.Name, "files", len(protoFiles), "skipLLM", skipLLM)

	var resp *requirementsv1.ExtractSpecsResponse
	err = r.runSyncLLMJob(ctx, llm.SubsystemRequirements, "extract_specs",
		fmt.Sprintf("requirements:extract:%s", input.RepositoryID), input.RepositoryID,
		func(rt llm.Runtime) error {
			var callErr error
			resp, callErr = r.Worker.ExtractSpecs(ctx, &requirementsv1.ExtractSpecsRequest{
				RepositoryId:      input.RepositoryID,
				RepositoryName:    repo.Name,
				Files:             protoFiles,
				SkipLlmRefinement: skipLLM,
			})
			return callErr
		})
	if err != nil {
		return nil, fmt.Errorf("spec extraction failed: %w", err)
	}

	// Store discovered specs
	var toStore []*graphstore.DiscoveredRequirement
	for _, spec := range resp.Specs {
		sourceFiles := spec.SourceFiles
		if sourceFiles == nil {
			sourceFiles = []string{}
		}
		keywords := spec.Keywords
		if keywords == nil {
			keywords = []string{}
		}
		toStore = append(toStore, &graphstore.DiscoveredRequirement{
			RepoID:      input.RepositoryID,
			Source:      spec.Source,
			SourceFile:  spec.SourceFile,
			SourceLine:  int(spec.SourceLine),
			SourceFiles: sourceFiles,
			Text:        spec.Text,
			RawText:     spec.RawText,
			GroupKey:    spec.GroupKey,
			Language:    spec.Language,
			Keywords:    keywords,
			Confidence:  spec.Confidence,
			Status:      "discovered",
			LLMRefined:  spec.LlmRefined,
		})
	}
	stored := store.StoreDiscoveredRequirements(input.RepositoryID, toStore)

	slog.Info("spec-extraction: complete", "discovered", stored, "candidates", resp.TotalCandidates)

	r.Resolver.publishEvent(events.EventSpecExtraction, map[string]interface{}{
		"repo_id": input.RepositoryID, "discovered": stored,
		"total_candidates": int(resp.TotalCandidates),
	})

	result := &SpecExtractionResult{
		Discovered:      stored,
		TotalCandidates: int(resp.TotalCandidates),
		Warnings:        resp.Warnings,
	}
	if result.Warnings == nil {
		result.Warnings = []string{}
	}
	if resp.Usage != nil {
		result.Model = &resp.Usage.Model
		in := int(resp.Usage.InputTokens)
		out := int(resp.Usage.OutputTokens)
		result.InputTokens = &in
		result.OutputTokens = &out
	}
	return result, nil
}

// PromoteDiscoveredRequirement is the resolver for the promoteDiscoveredRequirement field.
func (r *mutationResolver) PromoteDiscoveredRequirement(ctx context.Context, id string, title *string, description *string) (*PromoteResult, error) {
	store := r.getStore(ctx)
	disc := store.GetDiscoveredRequirement(id)
	if disc == nil {
		return nil, fmt.Errorf("discovered requirement not found: %s", id)
	}
	if disc.Status != "discovered" {
		return nil, fmt.Errorf("cannot promote: status is %s", disc.Status)
	}

	// Build a stored requirement from the discovered spec
	reqTitle := disc.Text
	if title != nil && *title != "" {
		reqTitle = *title
	}
	reqDesc := disc.RawText
	if description != nil && *description != "" {
		reqDesc = *description
	}

	req := &graphstore.StoredRequirement{
		Title:       reqTitle,
		Description: reqDesc,
		Source:      "spec-extraction:" + disc.Source,
		Priority:    "medium",
		Tags:        disc.Keywords,
	}
	store.StoreRequirement(disc.RepoID, req)

	// Mark the discovered requirement as promoted
	updated := store.PromoteDiscoveredRequirement(id, req.ID)

	return &PromoteResult{
		Requirement:           mapRequirement(req),
		DiscoveredRequirement: mapDiscoveredRequirement(updated),
	}, nil
}

// DismissDiscoveredRequirement is the resolver for the dismissDiscoveredRequirement field.
func (r *mutationResolver) DismissDiscoveredRequirement(ctx context.Context, id string, reason *string) (*DiscoveredRequirement, error) {
	store := r.getStore(ctx)
	disc := store.GetDiscoveredRequirement(id)
	if disc == nil {
		return nil, fmt.Errorf("discovered requirement not found: %s", id)
	}

	dismissReason := ""
	if reason != nil {
		dismissReason = *reason
	}
	updated := store.DismissDiscoveredRequirement(id, "user", dismissReason)
	if updated == nil {
		return nil, fmt.Errorf("failed to dismiss discovered requirement")
	}
	return mapDiscoveredRequirement(updated), nil
}

