// Health is the resolver for the health field.
func (r *queryResolver) Health(ctx context.Context) (*HealthStatus, error) {
	services := []*ServiceHealth{
		{Name: "api", Status: "healthy"},
	}

	// Check database
	dbStatus := "healthy"
	if r.getStore(ctx) == nil {
		dbStatus = "unavailable"
	}
	services = append(services, &ServiceHealth{Name: "database", Status: dbStatus})

	// Check worker
	workerStatus := "unavailable"
	if r.Worker != nil {
		healthy, err := r.Worker.CheckHealth(ctx)
		if err == nil && healthy {
			workerStatus = "healthy"
		} else if err != nil {
			workerStatus = "unhealthy"
		}
	}
	services = append(services, &ServiceHealth{Name: "worker", Status: workerStatus})

	overallStatus := "healthy"
	if dbStatus != "healthy" {
		overallStatus = "degraded"
	}

	return &HealthStatus{
		Status:   overallStatus,
		Services: services,
	}, nil
}

