// SourceFile is the resolver for the sourceFile field.
func (r *queryResolver) SourceFile(ctx context.Context, repositoryID string, filePath string) (*SourceFileResult, error) {
	store := r.getStore(ctx)
	if store == nil {
		code := "STORE_UNAVAILABLE"
		message := "source storage is unavailable"
		return &SourceFileResult{Ok: false, ErrorCode: &code, Message: &message}, nil
	}

	repo := store.GetRepository(repositoryID)
	if repo == nil {
		code := "REPOSITORY_NOT_FOUND"
		message := "repository not found"
		return &SourceFileResult{Ok: false, ErrorCode: &code, Message: &message}, nil
	}

	repoRoot, err := resolveRepoSourcePath(repo)
	if err != nil {
		code := "SOURCE_UNAVAILABLE"
		message := err.Error()
		return &SourceFileResult{Ok: false, ErrorCode: &code, Message: &message}, nil
	}

	maxBytes := int64(1024 * 1024)
	if r.Config != nil && r.Config.Indexing.MaxFileSize > 0 {
		maxBytes = r.Config.Indexing.MaxFileSize
	}

	content, err := readSourceFileLimited(repoRoot, filePath, maxBytes)
	if err != nil {
		code := "SOURCE_READ_FAILED"
		message := err.Error()
		switch {
		case strings.Contains(err.Error(), "path traversal"):
			code = "INVALID_PATH"
			message = "invalid repository-relative path"
		case strings.Contains(err.Error(), "absolute path"):
			code = "INVALID_PATH"
			message = "absolute paths are not allowed"
		case strings.Contains(err.Error(), "exceeds max size"):
			code = "FILE_TOO_LARGE"
			message = fmt.Sprintf("file exceeds the %d byte source-view limit", maxBytes)
		case strings.Contains(err.Error(), "binary file"):
			code = "BINARY_FILE"
			message = "binary files are not supported in the source viewer"
		case strings.Contains(err.Error(), "no such file"), strings.Contains(err.Error(), "reading file info"):
			code = "FILE_NOT_FOUND"
			message = "file not found in repository source"
		}
		return &SourceFileResult{Ok: false, ErrorCode: &code, Message: &message}, nil
	}

	var fileMeta *graphstore.File
	for _, f := range store.GetFiles(repositoryID) {
		if f != nil && f.Path == filePath {
			fileMeta = f
			break
		}
	}

	lineCount := strings.Count(content, "\n")
	if content != "" {
		lineCount++
	}
	lang := LanguageUnknown
	if fileMeta != nil {
		if l := Language(strings.ToUpper(fileMeta.Language)); l.IsValid() {
			lang = l
		}
		if fileMeta.LineCount > 0 {
			lineCount = fileMeta.LineCount
		}
	} else {
		derived := strings.TrimPrefix(strings.TrimPrefix(deriveLanguage(filePath).String(), "LANGUAGE_"), "LANGUAGE")
		if l := Language(derived); l.IsValid() {
			lang = l
		}
	}

	var contentHash *string
	if fileMeta != nil && fileMeta.ContentHash != "" {
		contentHash = &fileMeta.ContentHash
	}

	return &SourceFileResult{
		Ok: true,
		File: &SourceFile{
			RepositoryID: repositoryID,
			FilePath:     filePath,
			Language:     lang,
			LineCount:    lineCount,
			Content:      content,
			ContentHash:  contentHash,
		},
	}, nil
}

// KnowledgeArtifacts is the resolver for the knowledgeArtifacts field.
func (r *queryResolver) KnowledgeArtifacts(ctx context.Context, repositoryID string, scopeType *KnowledgeScopeType, scopePath *string) ([]*KnowledgeArtifact, error) {
	if r.KnowledgeStore == nil {
		return []*KnowledgeArtifact{}, nil
	}
	artifacts := r.KnowledgeStore.GetKnowledgeArtifacts(repositoryID)
	if scopeType == nil && scopePath == nil {
		result := make([]*KnowledgeArtifact, len(artifacts))
		for i, a := range artifacts {
			result[i] = mapKnowledgeArtifactWithStore(r.KnowledgeStore, a)
		}
		return result, nil
	}
	scope, err := artifactScopeFromInput(scopeType, scopePath)
	if err != nil {
		return nil, err
	}
	var result []*KnowledgeArtifact
	for _, a := range artifacts {
		artifactScope := knowledgepkg.ArtifactScope{ScopeType: knowledgepkg.ScopeRepository}
		if a.Scope != nil {
			artifactScope = a.Scope.Normalize()
		}
		if artifactScope.ScopeKey() == scope.ScopeKey() {
			result = append(result, mapKnowledgeArtifactWithStore(r.KnowledgeStore, a))
		}
	}
	if result == nil {
		result = []*KnowledgeArtifact{}
	}
	return result, nil
}

