// KnowledgeScopeChildren is the resolver for the knowledgeScopeChildren field.
func (r *queryResolver) KnowledgeScopeChildren(ctx context.Context, repositoryID string, scopeType KnowledgeScopeType, scopePath string, audience *KnowledgeAudience, depth *KnowledgeDepth) ([]*ScopeChild, error) {
	store := r.getStore(ctx)
	if store == nil {
		return []*ScopeChild{}, nil
	}
	if r.KnowledgeStore == nil {
		return []*ScopeChild{}, nil
	}
	scope := knowledgepkg.ArtifactScope{
		ScopeType: scopeTypeToGraph(scopeType),
		ScopePath: scopePath,
	}.Normalize()
	children := buildScopeChildren(store, repositoryID, scope)
	result := make([]*ScopeChild, 0, len(children))
	childAudience := knowledgeAudienceValue(audience)
	childDepth := knowledgeDepthValue(depth)
	for _, child := range children {
		key := knowledgepkg.ArtifactKey{
			RepositoryID: repositoryID,
			Type:         knowledgepkg.ArtifactCliffNotes,
			Audience:     childAudience,
			Depth:        childDepth,
			Scope:        child,
		}.Normalized()
		existing := r.KnowledgeStore.GetArtifactByKey(key)
		hasArtifact := existing != nil && existing.Status == knowledgepkg.StatusReady && !existing.Stale
		var summary *string
		if hasArtifact && len(existing.Sections) > 0 {
			if existing.Sections[0].Summary != "" {
				summary = &existing.Sections[0].Summary
			} else if existing.Sections[0].Content != "" {
				text := existing.Sections[0].Content
				if len(text) > 120 {
					text = text[:120] + "..."
				}
				summary = &text
			}
		}
		result = append(result, &ScopeChild{
			ScopeType:   mapScopeType(child.ScopeType),
			Label:       scopeLabel(child),
			ScopePath:   child.ScopePath,
			HasArtifact: hasArtifact,
			Summary:     summary,
		})
	}
	return result, nil
}

