// AiGeneratedFiles is the resolver for the aiGeneratedFiles field.
func (r *queryResolver) AiGeneratedFiles(ctx context.Context, repositoryID string, minScore *float64) ([]*File, error) {
	store := r.getStore(ctx)
	if store == nil {
		return nil, fmt.Errorf("store not initialized")
	}

	threshold := 0.5
	if minScore != nil && *minScore > 0 {
		threshold = *minScore
	}

	allFiles := store.GetFiles(repositoryID)
	var result []*File
	for _, f := range allFiles {
		if f.AIScore >= threshold {
			result = append(result, mapFile(f))
		}
	}
	if result == nil {
		result = []*File{}
	}
	return result, nil
}

